const registros = $input.all().map(i => i.json);
const hoy = new Date();
const mesActual = hoy.getMonth();
const anioActual = hoy.getFullYear();

// Filtrar registros del mes en curso
const delMes = registros.filter(r => {
  const partes = (r.fecha || '').split('/');
  if (partes.length < 3) return false;
  const mes = parseInt(partes[1], 10) - 1;
  const anio = parseInt(partes[2], 10);
  return mes === mesActual && anio === anioActual;
});

// Agrupar por alumno
const porAlumno = {};
for (const r of delMes) {
  const nombre = r.alumno || 'Desconocido';
  if (!porAlumno[nombre]) {
    porAlumno[nombre] = { alumno: nombre, curso: r.curso || '', total: 0, ausencias: 0 };
  }
  porAlumno[nombre].total++;
  if (r.presente === false || r.presente === 'false' || r.presente === 'FALSE') {
    porAlumno[nombre].ausencias++;
  }
}

// Filtrar los que superan el umbral de 3 ausencias
const UMBRAL = 3;
const alertas = Object.values(porAlumno)
  .filter(a => a.ausencias >= UMBRAL)
  .map(a => ({
    alumno: a.alumno,
    curso: a.curso,
    ausencias: a.ausencias,
    dias_registrados: a.total,
    porcentaje_asistencia: Math.round(((a.total - a.ausencias) / a.total) * 100) + '%'
  }))
  .sort((a, b) => b.ausencias - a.ausencias);

return alertas.map(a => ({ json: a }));

const alertas = $input.all().map(i => i.json);
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const mes = meses[new Date().getMonth()];

let tabla = '| Alumno | Curso | Ausencias | Asistencia |\n';
tabla += '|--------|-------|-----------|------------|\n';
for (const a of alertas) {
  tabla += `| ${a.alumno} | ${a.curso} | ${a.ausencias} faltas | ${a.porcentaje_asistencia} |\n`;
}

const cuerpo = `INFORME DE ABSENTISMO - ${mes.toUpperCase()} ${new Date().getFullYear()}\n\n`
  + `Se han detectado ${alertas.length} alumno(s) con 3 o mas ausencias en el mes de ${mes}:\n\n`
  + tabla
  + `\nEste informe se genera automaticamente cada viernes. Se recomienda contactar con las familias de los alumnos listados.`;

return [{ json: { asunto: `ALERTA ABSENTISMO - ${alertas.length} alumno(s) con faltas acumuladas en ${mes}`, cuerpo, total_alertas: alertas.length } }];
